A `debounce` function delays the execution of a function until a certain amount of time has passed without further calls.

```javascript
function debounce(func, delay) {
  let timeout;
  return function(...args) {
    const context = this;
    clearTimeout(timeout);
    timeout = setTimeout(() => func.apply(context, args), delay);
  };
}

// Example Usage:

function searchInputHandler(searchTerm) {
  console.log("Searching for:", searchTerm);
}

// Create a debounced version of the searchInputHandler, with a 500ms delay
const debouncedSearch = debounce(searchInputHandler, 500);

// Simulate rapid key presses in a search box
debouncedSearch("apple");
debouncedSearch("appl");
debouncedSearch("app");
debouncedSearch("appl");
debouncedSearch("apple"); // This will be the only one that triggers after 500ms of no further calls

// After 500ms, you will see "Searching for: apple" logged to the console
```
